import threading
import sqlite3
from contextlib import contextmanager
from typing import Optional, Dict, Any

class FinancialTransactionProcessor:
    def __init__(self, db_path: str):
        self.db_path = db_path
        self.lock = threading.RLock()
        self._init_db()
    
    def _init_db(self):
        with self._get_db() as conn:
            conn.execute('''
                CREATE TABLE IF NOT EXISTS accounts (
                    account_id TEXT PRIMARY KEY,
                    balance REAL NOT NULL DEFAULT 0.0,
                    version INTEGER NOT NULL DEFAULT 0
                )
            ''')
            conn.execute('''
                CREATE TABLE IF NOT EXISTS transactions (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    account_id TEXT,
                    transaction_type TEXT,
                    amount REAL,
                    timestamp DATETIME DEFAULT CURRENT_TIMESTAMP,
                    FOREIGN KEY (account_id) REFERENCES accounts (account_id)
                )
            ''')
    
    @contextmanager
    def _get_db(self):
        conn = sqlite3.connect(self.db_path)
        conn.execute('PRAGMA foreign_keys = ON')
        try:
            yield conn
        finally:
            conn.close()
    
    def _validate_and_update_balance(self, account_id: str, amount: float, 
                                   transaction_type: str, expected_version: Optional[int] = None) -> bool:
        with self.lock:
            with self._get_db() as conn:
                # Get current account state with version
                cursor = conn.execute(
                    'SELECT balance, version FROM accounts WHERE account_id = ?',
                    (account_id,)
                )
                result = cursor.fetchone()
                
                if not result:
                    # Create account if it doesn't exist
                    conn.execute(
                        'INSERT INTO accounts (account_id, balance, version) VALUES (?, ?, ?)',
                        (account_id, 0.0, 0)
                    )
                    current_balance = 0.0
                    current_version = 0
                else:
                    current_balance, current_version = result
                
                # Validate version if provided (optimistic locking)
                if expected_version is not None and expected_version != current_version:
                    return False
                
                # Calculate new balance
                if transaction_type == 'purchase':
                    new_balance = current_balance - amount
                elif transaction_type == 'redemption':
                    new_balance = current_balance + amount
                else:
                    raise ValueError(f"Invalid transaction type: {transaction_type}")
                
                # Check for negative balance (insufficient funds)
                if new_balance < 0:
                    return False
                
                # Update balance with version increment (atomic operation)
                new_version = current_version + 1
                conn.execute(
                    'UPDATE accounts SET balance = ?, version = ? WHERE account_id = ? AND version = ?',
                    (new_balance, new_version, account_id, current_version)
                )
                
                # Check if update was successful (row count should be 1)
                if conn.total_changes == 0:
                    return False
                
                # Record transaction
                conn.execute(
                    'INSERT INTO transactions (account_id, transaction_type, amount) VALUES (?, ?, ?)',
                    (account_id, transaction_type, amount)
                )
                
                return True
    
    def purchase(self, account_id: str, amount: float, expected_version: Optional[int] = None) -> bool:
        """Process a purchase transaction"""
        if amount <= 0:
            raise ValueError("Purchase amount must be positive")
        return self._validate_and_update_balance(account_id, amount, 'purchase', expected_version)
    
    def redemption(self, account_id: str, amount: float, expected_version: Optional[int] = None) -> bool:
        """Process a redemption transaction"""
        if amount <= 0:
            raise ValueError("Redemption amount must be positive")
        return self._validate_and_update_balance(account_id, amount, 'redemption', expected_version)
    
    def get_account_balance(self, account_id: str) -> Optional[float]:
        """Get current account balance"""
        with self._get_db() as conn:
            cursor = conn.execute(
                'SELECT balance FROM accounts WHERE account_id = ?',
                (account_id,)
            )
            result = cursor.fetchone()
            return result[0] if result else None
    
    def get_account_version(self, account_id: str) -> Optional[int]:
        """Get current account version"""
        with self._get_db() as conn:
            cursor = conn.execute(
                'SELECT version FROM accounts WHERE account_id = ?',
                (account_id,)
            )
            result = cursor.fetchone()
            return result[0] if result else None

